    // ═════════════════════════════════════════════════════════════════════════════════════════════════════════════════╗
    /* INJECT PERM LIMIT CHECK */
    // ═════════════════════════════════════════════════════════════════════════════════════════════════════════════════╝
    // END PERM LIMIT CHECK

